import sys
from collections import deque, defaultdict
from typing import List

class Solution:
    def findLadders(self, beginWord: str, endWord: str, wordList: List[str]) -> List[List[str]]:
        word_set = set(wordList)
        if endWord not in word_set:
            return []
        if not beginWord or not endWord or not wordList:
            return []
        queue = deque([[beginWord]])
        visited = set([beginWord])
        found = False
        result = []
        min_length = float('inf')
        while queue:
            level_size = len(queue)
            level_visited = set()
            for _ in range(level_size):
                path = queue.popleft()
                word = path[-1]
                if word == endWord:
                    if len(path) < min_length:
                        result = [path]
                        min_length = len(path)
                    elif len(path) == min_length:
                        result.append(path)
                    found = True
                for i in range(len(word)):
                    for c in 'abcdefghijklmnopqrstuvwxyz':
                        next_word = word[:i] + c + word[i+1:]
                        if next_word in word_set and next_word not in visited:
                            level_visited.add(next_word)
                            queue.append(path + [next_word])
            if found:
                break
            visited.update(level_visited)
        return result

if __name__ == '__main__':
    beginWord = sys.stdin.readline().strip()
    endWord = sys.stdin.readline().strip()
    n = int(sys.stdin.readline().strip())
    wordList = [sys.stdin.readline().strip() for _ in range(n)]
    sol = Solution()
    ans = sol.findLadders(beginWord, endWord, wordList)
    if not ans:
        print("[]")
    else:
        ans.sort()
        for path in ans:
            print(' '.join(path))

