#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<vector<string>> findLadders(string beginWord, string endWord, vector<string>& wordList) {
        unordered_set<string> word_set(wordList.begin(), wordList.end());
        if (word_set.find(endWord) == word_set.end()) {
            return {};
        }
        queue<vector<string>> q;
        q.push({beginWord});
        unordered_set<string> visited;
        visited.insert(beginWord);
        bool found = false;
        vector<vector<string>> result;
        int min_length = INT_MAX;
        while (!q.empty()) {
            int level_size = q.size();
            unordered_set<string> level_visited;
            for (int i = 0; i < level_size; i++) {
                auto path = q.front(); q.pop();
                string word = path.back();
                if (word == endWord) {
                    if (path.size() < min_length) {
                        result = {path};
                        min_length = path.size();
                    } else if (path.size() == min_length) {
                        result.push_back(path);
                    }
                    found = true;
                }
                for (int j = 0; j < word.size(); j++) {
                    for (char c = 'a'; c <= 'z'; c++) {
                        string next_word = word.substr(0, j) + c + word.substr(j + 1);
                        if (word_set.find(next_word) != word_set.end() && visited.find(next_word) == visited.end()) {
                            level_visited.insert(next_word);
                            path.push_back(next_word);
                            q.push(path);
                            path.pop_back();
                        }
                    }
                }
            }
            if (found) {
                break;
            }
            visited.insert(level_visited.begin(), level_visited.end());
        }
        return result;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    string beginWord, endWord;
    cin >> beginWord >> endWord;
    int n;
    cin >> n;
    vector<string> wordList(n);
    for (int i = 0; i < n; i++) {
        cin >> wordList[i];
    }
    Solution sol;
    auto ans = sol.findLadders(beginWord, endWord, wordList);
    if (ans.empty()) {
        cout << "[]" << '\n';
    } else {
        sort(ans.begin(), ans.end());
        for (const auto& path : ans) {
            for (const auto& word : path) {
                cout << word << ' ';
            }
            cout << '\n';
        }
    }
    return 0;
}
